{
  "grammar": [
    {
      "pattern": "本來 + [situation A] + 後來 + [situation B]",
      "structure": ["本來", "situation A", "後來", "situation B"],
      "explanation_en": "Use '本來' to describe an original plan or state, and '後來' to indicate a change or subsequent event. This structure is common in storytelling to show contrast between past and later developments.",
      "title": "本來...後來... (Originally... Later...)",
      "meaning": "Shows a change from an original situation to a later one.",
      "when_to_use": ["When telling a story about a change in plans or events", "When contrasting a past state with what happened afterwards"],
      "when_not_to_use": ["When describing a single continuous event without change", "When the order of events is not important"],
      "pragmatic_notes": "In Taiwan, this pattern is very common in casual storytelling. It often implies a slight surprise or unexpected change, but can also be neutral.",
      "word_order_notes": "Place '本來' at the beginning of the first clause, and '後來' at the beginning of the second clause. The subject is usually the same for both clauses.",
      "english_contrast": "English uses 'originally... but later...' or 'at first... then...' to express the same contrast.",
      "korean_contrast": "Korean uses '원래... 그런데 나중에...' (wonrae... geureonde najunge...) for a similar contrast.",
      "negative_examples": [
        {
          "text": "我本來去公園，後來去商店。",
          "error": "Missing '了' after '去' to indicate completed action in the second clause. Should be '我本來去公園，後來去了商店。'"
        },
        {
          "text": "本來我開心，後來我難過。",
          "error": "Missing '很' before adjectives '開心' and '難過' to make them predicates. Should be '本來我很開心，後來我很難過。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我本來去公園，後來去商店。",
          "error": "Missing '了' after '去' in the second clause to indicate completed action."
        },
        {
          "text": "本來我開心，後來我難過。",
          "error": "Missing '很' before adjectives '開心' and '難過'."
        }
      ],
      "transformation_drills": ["Change '我本來想喝咖啡，後來喝茶了。' to use '但是' instead of '後來'", "Rewrite '他本來在家，後來出門了。' using '以前' and '以後'"],
      "production_drills": ["Tell a short story about your morning using '本來...後來...'", "Describe a change in your weekend plans using this pattern"],
      "common_error_patterns": ["Forgetting '了' in the second clause for completed actions", "Omitting '很' before adjectives"],
      "repair_feedback": {
        "word_order": "Make sure '本來' comes before the first situation and '後來' before the second.",
        "politeness": "This pattern is neutral and can be used in both formal and informal contexts.",
        "vocabulary": "Use '本來' for original plans/states, and '後來' for changes. Avoid using '然後' for contrast."
      }
    },
    {
      "pattern": "因為 + [reason] + 所以 + [result]",
      "structure": ["因為", "reason", "所以", "result"],
      "explanation_en": "Use '因為...所以...' to express cause and effect. This is a fundamental structure in storytelling to explain why something happened.",
      "title": "因為...所以... (Because... So...)",
      "meaning": "Indicates a cause-and-effect relationship.",
      "when_to_use": ["When explaining the reason for an event or feeling", "When connecting two events where one causes the other"],
      "when_not_to_use": ["When the relationship is not causal but sequential", "When the reason is obvious from context"],
      "pragmatic_notes": "In Taiwan, '因為...所以...' is used in both spoken and written Chinese. In casual speech, '所以' is often used alone without '因為' if the reason is clear.",
      "word_order_notes": "The reason clause comes first, followed by the result clause. The subject can be placed before or after '因為'.",
      "english_contrast": "English uses 'because... so...' but note that in English, 'so' is not used with 'because' in the same sentence. In Chinese, both are used together.",
      "korean_contrast": "Korean uses '...기 때문에 ... (그래서) ...' (...
gi ttaemune ... (geuraeseo) ...) for cause and effect.",
      "negative_examples": [
        {
          "text": "因為我忘記帶傘，所以我濕了。",
          "error": "The result '濕了' is too vague. Should specify '所以我全身濕了' or '所以衣服濕了' for clarity."
        },
        {
          "text": "因為他難過，所以他哭。",
          "error": "Missing '了' after '哭' to indicate completed action. Should be '所以他哭了。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為我忘記帶傘，所以我濕了。",
          "error": "Result is too vague; specify what got wet."
        },
        {
          "text": "因為他難過，所以他哭。",
          "error": "Missing '了' after '哭' to indicate completed action."
        }
      ],
      "transformation_drills": ["Change '因為下雨，所以我不出門。' to use '所以' only", "Rewrite '因為他生病，所以他沒來上課。' using '所以' at the beginning"],
      "production_drills": ["Explain why you were late today using '因為...所以...'", "Tell a story about a happy event and its cause"],
      "common_error_patterns": ["Using '所以' without '因為' when the reason is not clear", "Forgetting '了' for completed actions in the result clause"],
      "repair_feedback": {
        "word_order": "Place '因為' before the reason and '所以' before the result.",
        "politeness": "This structure is neutral and appropriate for all contexts.",
        "vocabulary": "Use '因為' for reasons and '所以' for results. Avoid using '然後' for causal relationships."
      }
    },
    {
      "pattern": "[event] + 覺得 + [feeling]",
      "structure": ["event", "覺得", "feeling"],
      "explanation_en": "Use '覺得' to express how you felt after an event. This structure is essential for describing emotional reactions in storytelling.",
      "title": "Event + 覺得 + Feeling (Expressing Feelings After an Event)",
      "meaning": "Describes a feeling resulting from an event.",
      "when_to_use": ["When telling a story and describing your emotional reaction", "When explaining how an event affected you"],
      "when_not_to_use": ["When describing a permanent state or opinion", "When the feeling is not directly related to the event"],
      "pragmatic_notes": "In Taiwan, '覺得' is commonly used in both formal and informal contexts. For stronger emotions, '覺得很' + adjective is preferred.",
      "word_order_notes": "The event is stated first, followed by '覺得' and then the feeling. The subject is usually the same for both parts.",
      "english_contrast": "English uses 'I felt... after...' or '... made me feel...' to express similar ideas.",
      "korean_contrast": "Korean uses '...고 나서 ...라고 느꼈다' (...go naseo ...rago neukkyeotda) for expressing feelings after an event.",
      "negative_examples": [
        {
          "text": "我出門覺得開心。",
          "error": "Missing '了' after '出門' to indicate completed action. Should be '我出門了，覺得很開心。'"
        },
        {
          "text": "他發現事情，覺得緊張。",
          "error": "Missing '了' after '發現' and '很' before '緊張'. Should be '他發現了事情，覺得很緊張。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我出門覺得開心。",
          "error": "Missing '了' after '出門' to indicate completed action."
        },
        {
          "text": "他發現事情，覺得緊張。",
          "error": "Missing '了' after '發現' and '很' before '緊張'."
        }
      ],
      "transformation_drills": ["Change '我回家後覺得很累。' to use '因為...所以...'", "Rewrite '他聽到故事覺得很難過。' using '後來'"],
      "production_drills": ["Tell a story about a recent event and how you felt using '覺得'", "Describe a time you felt happy after an event"],
      "common_error_patterns": ["Forgetting '了' for completed events", "Omitting '很' before adjectives for feelings"],
      "repair_feedback": {
        "word_order": "Place the event first, then '覺得', then the feeling.",
        "politeness": "This structure is neutral and can be used in both casual and formal storytelling.",
        "vocabulary": "Use '覺得' for feelings after events. For stronger emotions, add '很' before the adjective."
      }
    }
  ]
}
